def facto(n):
    """
    calcul de la factorielle de l'entier n
    """ 
    if type(n)!= int :
        print(f"Ce n'est pas un nombre entier : {n}")
    else:
        if n < 0:
            print(f"entier negatif : {n}")
        else:
            c = 1
            for i in range(2, n+1):
                c = c * i
            return c

m = 13
import math
if facto(m)==math.factorial(m):
    print("ca a l'air de marcher!")
else:
